1	------------------------------------------------------------------------------
2	--  Copyright (c) 2019 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11		use ieee.std_logic_1164.all;
12		use ieee.numeric_std.all;
13		
14	library std;
15		use std.textio.all;
16		
17	library work;
18		use work.psi_tb_axi_pkg.all;
19		use work.psi_tb_txt_util.all;
20		use work.top_tb_pkg.all;
21		use work.data_rec_register_pkg.all;
22	
23	------------------------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------------------------
26	package top_tb_case1_pkg is
27	
28		constant CaseName_c : string := "Corner Conditions";
29	
30		procedure run(	signal ms		: out	axi_ms_r;
31						signal sm		: in	axi_sm_r;
32						signal aclk		: in	std_logic;
33						signal Clk 		: in 	std_logic;
34						signal ToDut	: out	In_t);
35						
36	end top_tb_case1_pkg;
37	
38	------------------------------------------------------------------------------
39	-- Package Body
40	------------------------------------------------------------------------------
41	package body top_tb_case1_pkg is
42	
43		procedure run(	signal ms		: out	axi_ms_r;
44						signal sm		: in	axi_sm_r;
45						signal aclk		: in	std_logic;
46						signal Clk 		: in 	std_logic;
47						signal ToDut	: out	In_t) is
48			constant DefaultSamples_c	: integer := MemoryDepth_v*3/4;
49			variable DutyCycle_v		: integer;
50		begin
51			-- Print Message
52			print("Test: " & CaseName_c);
53			
54			-- Test with different duty cycles
55			for d in 0 to 1 loop
56				DutyCycle_v := d*10+1;
57				
58				-- Normal Samples, Zero Pre-Trigger
59				axi_single_write(Reg_Totspl_Addr_c, DefaultSamples_c, ms, sm, aclk);
60				axi_single_write(Reg_Pretrig_Addr_c, 0, ms, sm, aclk);
61				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
62				wait for 250 ns;
63				InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v, DutyCycle_v);
64				wait for 250 ns;	
65				CheckData(DefaultSamples_c, MemoryDepth_v, ms, sm, aclk);
66				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
67				
68				-- Normal Samples, Maximum Pre-Trigger
69				axi_single_write(Reg_Totspl_Addr_c, DefaultSamples_c, ms, sm, aclk);
70				axi_single_write(Reg_Pretrig_Addr_c, DefaultSamples_c-1, ms, sm, aclk);
71				wait for 100 ns;
72				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
73				wait for 250 ns;
74				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StatePreTrig_c, ms, sm, aclk, "Direct Re-Arm without PreTrig Status", 3, 0);
75				InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v, DutyCycle_v);
76				wait for 250 ns;	
77				CheckData(DefaultSamples_c, MemoryDepth_v-DefaultSamples_c+1, ms, sm, aclk);	
78				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
79				
80				-- Only one sample (in the middle)
81				axi_single_write(Reg_Totspl_Addr_c, 1, ms, sm, aclk);
82				axi_single_write(Reg_Pretrig_Addr_c, 0, ms, sm, aclk);	
83				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);	
84				wait for 250 ns;		
85				InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v, DutyCycle_v);
86				wait for 250 ns;	
87				CheckData(1, MemoryDepth_v, ms, sm, aclk);			
88				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
89				
90				-- Only one sample (first one)
91				axi_single_write(Reg_Totspl_Addr_c, 1, ms, sm, aclk);
92				axi_single_write(Reg_Pretrig_Addr_c, 0, ms, sm, aclk);	
93				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);	
94				wait for 250 ns;		
95				InputSamples(1, ToDut, Clk, 100, 0, DutyCycle_v);
96				wait for 250 ns;	
97				CheckData(1, 100, ms, sm, aclk);			
98				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);
99				
100				-- Normal Samples, no additional samples arrive
101				axi_single_write(Reg_Totspl_Addr_c, DefaultSamples_c, ms, sm, aclk);
102				axi_single_write(Reg_Pretrig_Addr_c, 10, ms, sm, aclk);
103				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
104				wait for 250 ns;
105				InputSamples(DefaultSamples_c, ToDut, Clk, 0, 10, DutyCycle_v);
106				wait for 250 ns;	
107				CheckData(DefaultSamples_c, 0, ms, sm, aclk);
108				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);		
109				
110				-- Maximum sample count, normal pre trigger
111				axi_single_write(Reg_Totspl_Addr_c, MemoryDepth_v, ms, sm, aclk);
112				axi_single_write(Reg_Pretrig_Addr_c, MemoryDepth_v/2, ms, sm, aclk);
113				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
114				wait for 250 ns;
115				InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v, DutyCycle_v);
116				wait for 250 ns;	
117				CheckData(DefaultSamples_c, MemoryDepth_v-MemoryDepth_v/2, ms, sm, aclk);
118				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);		
119				
120				-- Maximum sample count, max pre-trigger
121				axi_single_write(Reg_Totspl_Addr_c, MemoryDepth_v, ms, sm, aclk);
122				axi_single_write(Reg_Pretrig_Addr_c, MemoryDepth_v-1, ms, sm, aclk);
123				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
124				wait for 250 ns;
125				InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v, DutyCycle_v);
126				wait for 250 ns;	
127				CheckData(DefaultSamples_c, 1, ms, sm, aclk);
128				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);			
129				
130				-- Maximum sample count, no pre-trigger
131				axi_single_write(Reg_Totspl_Addr_c, MemoryDepth_v, ms, sm, aclk);
132				axi_single_write(Reg_Pretrig_Addr_c, 0, ms, sm, aclk);
133				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
134				wait for 250 ns;
135				InputSamples(MemoryDepth_v*2, ToDut, Clk, 0, MemoryDepth_v, DutyCycle_v);
136				wait for 250 ns;	
137				CheckData(DefaultSamples_c, MemoryDepth_v, ms, sm, aclk);
138				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done Status", 3, 0);		
139				
140				-- Minimum Trigger Recording Period not respected
141				axi_single_write(Reg_MinRecPeriod_Addr_c, integer((50 us)/ClockPeriod_c), ms, sm, aclk);
142				axi_single_write(Reg_Totspl_Addr_c, 1, ms, sm, aclk);
143				axi_single_write(Reg_Pretrig_Addr_c, 0, ms, sm, aclk);
144				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
145				wait for 250 ns;
146				InputSamples(10, ToDut, Clk, 0, 2);
147				wait for 250 ns;
148				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Done For first recording", 3, 0);	
149				wait for 250 ns;
150				axi_single_write(Reg_Cfg_Addr_c, 1*2**Reg_Cfg_ArmIdx_c, ms, sm, aclk);
151				wait for 250 ns;
152				InputSamples(10, ToDut, Clk, 0, 2);
153				wait for 250 ns;
154				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateWaitTrig_c, ms, sm, aclk, "Period Not Respected", 3, 0);	-- No trigger period not respected
155				wait for 50 us;
156				InputSamples(10, ToDut, Clk, 0, 2);
157				wait for 250 ns;
158				axi_single_expect(Reg_Stat_Addr_c, Reg_Stat_StateDone_c, ms, sm, aclk, "Recording happens after period", 3, 0);	-- No trigger period not respected
159				axi_single_write(Reg_MinRecPeriod_Addr_c, 0, ms, sm, aclk);
160				
161				
162			end loop;
163			
164			
165		end procedure;
166		
167		
168	end top_tb_case1_pkg;
